     1→// ── CRM page (Preact + HTM + Signals) ────────────────────────
     2→
     3→import { signal } from "@preact/signals";
     4→import { html } from "htm/preact";
     5→import { render } from "preact";
     6→import { useEffect, useRef, useState } from "preact/hooks";
     7→import * as gon from "./gon.js";
     8→import { sendRpc } from "./helpers.js";
     9→import { useTranslation } from "./i18n.js";
    10→import { updateNavCount } from "./nav-counts.js";
    11→import { navigate, registerPrefix } from "./router.js";
    12→import { routes } from "./routes.js";
    13→import { ConfirmDialog, requestConfirm, showToast } from "./ui.js";
    14→
    15→// ── Module-level signals ─────────────────────────────────────
    16→var contacts = signal([]);
    17→var loadingContacts = signal(true);
    18→var searchQuery = signal("");
    19→var stageFilter = signal("");
    20→var currentContactId = signal(null);
    21→var contactDetail = signal(null);
    22→var loadingDetail = signal(false);
    23→var matters = signal([]);
    24→var interactions = signal([]);
    25→var channels = signal([]);
    26→var loadingMatters = signal(false);
    27→var loadingInteractions = signal(false);
    28→var loadingChannels = signal(false);
    29→var detailTab = signal("overview");
    30→
    31→// ── Enum label/color maps ─────────────────────────────────────
    32→
    33→var STAGE_COLORS = {
    34→	lead: "bg-blue-100 text-blue-800 dark:bg-blue-900 dark:text-blue-200",
    35→	prospect: "bg-purple-100 text-purple-800 dark:bg-purple-900 dark:text-purple-200",
    36→	active: "bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-200",
    37→	inactive: "bg-amber-100 text-amber-800 dark:bg-amber-900 dark:text-amber-200",
    38→	closed: "bg-gray-100 text-gray-600 dark:bg-gray-800 dark:text-gray-400",
    39→};
    40→
    41→var MATTER_STATUS_COLORS = {
    42→	open: "bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-200",
    43→	on_hold: "bg-amber-100 text-amber-800 dark:bg-amber-900 dark:text-amber-200",
    44→	closed: "bg-gray-100 text-gray-600 dark:bg-gray-800 dark:text-gray-400",
    45→	archived: "bg-gray-100 text-gray-500 dark:bg-gray-800 dark:text-gray-500",
    46→};
    47→
    48→var INTERACTION_KIND_ICONS = {
    49→	call: "icon-phone",
    50→	email: "icon-mail",
    51→	message: "icon-chat-bubble",
    52→	meeting: "icon-users",
    53→	note: "icon-file",
    54→	document: "icon-file",
    55→};
    56→
    57→// ── Helpers ───────────────────────────────────────────────────
    58→
    59→function newId() {
    60→	return crypto.randomUUID ? crypto.randomUUID() : `${Date.now()}-${Math.random().toString(36).slice(2)}`;
    61→}
    62→
    63→function initials(name) {
    64→	if (!name) return "?";
    65→	var parts = name.trim().split(/\s+/);
    66→	if (parts.length >= 2) return (parts[0][0] + parts[parts.length - 1][0]).toUpperCase();
    67→	return name.slice(0, 2).toUpperCase();
    68→}
    69→
    70→var AVATAR_COLORS = [
    71→	"bg-blue-500",
    72→	"bg-purple-500",
    73→	"bg-green-500",
    74→	"bg-amber-500",
    75→	"bg-rose-500",
    76→	"bg-teal-500",
    77→	"bg-indigo-500",
    78→	"bg-orange-500",
    79→];
    80→
    81→function avatarColor(id) {
    82→	var hash = 0;
    83→	for (var i = 0; i < (id || "").length; i++) {
    84→		hash = (hash * 31 + id.charCodeAt(i)) & 0xffffffff;
    85→	}
    86→	return AVATAR_COLORS[Math.abs(hash) % AVATAR_COLORS.length];
    87→}
    88→
    89→function formatDate(epochMs) {
    90→	if (!epochMs) return "";
    91→	return new Date(epochMs).toLocaleDateString(undefined, { year: "numeric", month: "short", day: "numeric" });
    92→}
    93→
    94→function formatDateTime(epochMs) {
    95→	if (!epochMs) return "";
    96→	return new Date(epochMs).toLocaleString(undefined, {
    97→		year: "numeric",
    98→		month: "short",
    99→		day: "numeric",
   100→		hour: "2-digit",
   101→		minute: "2-digit",
   102→	});
   103→}
   104→
   105→// Client-side filter for contacts list
   106→function filterContacts(list, query, stage) {
   107→	var q = (query || "").toLowerCase().trim();
   108→	return list.filter((c) => {
   109→		if (stage && c.stage !== stage) return false;
   110→		if (!q) return true;
   111→		var name = (c.name || "").toLowerCase();
   112→		var email = (c.email || "").toLowerCase();
   113→		var phone = (c.phone || "").toLowerCase();
   114→		return name.includes(q) || email.includes(q) || phone.includes(q);
   115→	});
   116→}
   117→
   118→// ── Data loading ──────────────────────────────────────────────
   119→
   120→function loadContacts() {
   121→	loadingContacts.value = true;
   122→	sendRpc("crm.contacts.list", {}).then((res) => {
   123→		loadingContacts.value = false;
   124→		if (!res?.ok) {
   125→			showToast("errors.loadFailed", "error");
   126→			return;
   127→		}
   128→		var list = Array.isArray(res.payload) ? res.payload : [];
   129→		contacts.value = list;
   130→		updateNavCount("crm", list.length);
   131→	});
   132→}
   133→
   134→function loadContactDetail(id) {
   135→	loadingDetail.value = true;
   136→	contactDetail.value = null;
   137→	sendRpc("crm.contacts.get", { id }).then((res) => {
   138→		loadingDetail.value = false;
   139→		if (!(res?.ok && res.payload)) {
   140→			navigate(routes.crm);
   141→			return;
   142→		}
   143→		contactDetail.value = res.payload;
   144→	});
   145→}
   146→
   147→function loadMatters(contactId) {
   148→	loadingMatters.value = true;
   149→	sendRpc("crm.matters.list", {}).then((res) => {
   150→		loadingMatters.value = false;
   151→		if (!res?.ok) return;
   152→		var all = Array.isArray(res.payload) ? res.payload : [];
   153→		matters.value = all.filter((m) => m.contactId === contactId);
   154→	});
   155→}
   156→
   157→function loadInteractions(contactId) {
   158→	loadingInteractions.value = true;
   159→	sendRpc("crm.interactions.list", { contactId }).then((res) => {
   160→		loadingInteractions.value = false;
   161→		if (!res?.ok) return;
   162→		interactions.value = Array.isArray(res.payload) ? res.payload : [];
   163→	});
   164→}
   165→
   166→function loadChannels(contactId) {
   167→	loadingChannels.value = true;
   168→	sendRpc("crm.channels.list", { contactId }).then((res) => {
   169→		loadingChannels.value = false;
   170→		if (!res?.ok) return;
   171→		channels.value = Array.isArray(res.payload) ? res.payload : [];
   172→	});
   173→}
   174→
   175→// ── StageBadge component ──────────────────────────────────────
   176→function StageBadge({ stage, t }) {
   177→	var color = STAGE_COLORS[stage] || STAGE_COLORS.lead;
   178→	var label = t(`contacts.stages.${stage}`) || stage;
   179→	return html`<span class="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium ${color}">${label}</span>`;
   180→}
   181→
   182→// ── Avatar component ──────────────────────────────────────────
   183→function Avatar({ name, id, size = "md" }) {
   184→	var color = avatarColor(id || name || "");
   185→	var sizeClass = size === "sm" ? "w-7 h-7 text-xs" : size === "lg" ? "w-12 h-12 text-lg" : "w-9 h-9 text-sm";
   186→	return html`<div class="rounded-full ${color} ${sizeClass} flex items-center justify-center text-white font-medium flex-shrink-0">
   187→		${initials(name)}
   188→	</div>`;
   189→}
