   191→// ── ContactForm modal ─────────────────────────────────────────
   192→function ContactForm({ contact, onClose, onSaved }) {
   193→	var { t } = useTranslation("crm");
   194→	var isEdit = !!contact?.id;
   195→
   196→	var [name, setName] = useState(contact?.name || "");
   197→	var [email, setEmail] = useState(contact?.email || "");
   198→	var [phone, setPhone] = useState(contact?.phone || "");
   199→	var [stage, setStage] = useState(contact?.stage || "lead");
   200→	var [source, setSource] = useState(contact?.source || "");
   201→	var [externalId, setExternalId] = useState(contact?.externalId || "");
   202→	var [saving, setSaving] = useState(false);
   203→	var [error, setError] = useState(null);
   204→
   205→	function onSubmit(e) {
   206→		e.preventDefault();
   207→		if (!name.trim()) {
   208→			setError(t("form.nameRequired"));
   209→			return;
   210→		}
   211→		setSaving(true);
   212→		setError(null);
   213→		var params = {
   214→			id: contact?.id || newId(),
   215→			name: name.trim(),
   216→			email: email.trim() || null,
   217→			phone: phone.trim() || null,
   218→			stage,
   219→			source: source.trim() || null,
   220→			externalId: externalId.trim() || null,
   221→			createdAt: contact?.createdAt,
   222→		};
   223→		sendRpc("crm.contacts.upsert", params).then((res) => {
   224→			setSaving(false);
   225→			if (!res?.ok) {
   226→				setError(t("errors.saveFailed"));
   227→				return;
   228→			}
   229→			onSaved();
   230→		});
   231→	}
   232→
   233→	var stages = ["lead", "prospect", "active", "inactive", "closed"];
   234→
   235→	return html`<form onSubmit=${onSubmit}>
   236→		<div class="flex flex-col gap-3 mb-4">
   237→			<div>
   238→				<label class="block text-xs text-[var(--muted)] mb-1">${t("form.name")} *</label>
   239→				<input
   240→					type="text"
   241→					value=${name}
   242→					onInput=${(e) => setName(e.target.value)}
   243→					placeholder=${t("form.namePlaceholder")}
   244→					class="w-full text-sm bg-[var(--surface2)] border border-[var(--border)] rounded px-2.5 py-1.5 text-[var(--text)] focus:outline-none focus:border-[var(--border-strong)]"
   245→					autofocus
   246→				/>
   247→			</div>
   248→			<div class="grid grid-cols-2 gap-3">
   249→				<div>
   250→					<label class="block text-xs text-[var(--muted)] mb-1">${t("form.email")}</label>
   251→					<input
   252→						type="email"
   253→						value=${email}
   254→						onInput=${(e) => setEmail(e.target.value)}
   255→						placeholder=${t("form.emailPlaceholder")}
   256→						class="w-full text-sm bg-[var(--surface2)] border border-[var(--border)] rounded px-2.5 py-1.5 text-[var(--text)] focus:outline-none focus:border-[var(--border-strong)]"
   257→					/>
   258→				</div>
   259→				<div>
   260→					<label class="block text-xs text-[var(--muted)] mb-1">${t("form.phone")}</label>
   261→					<input
   262→						type="tel"
   263→						value=${phone}
   264→						onInput=${(e) => setPhone(e.target.value)}
   265→						placeholder=${t("form.phonePlaceholder")}
   266→						class="w-full text-sm bg-[var(--surface2)] border border-[var(--border)] rounded px-2.5 py-1.5 text-[var(--text)] focus:outline-none focus:border-[var(--border-strong)]"
   267→					/>
   268→				</div>
   269→			</div>
   270→			<div>
   271→				<label class="block text-xs text-[var(--muted)] mb-1">${t("form.stage")}</label>
   272→				<select
   273→					value=${stage}
   274→					onChange=${(e) => setStage(e.target.value)}
   275→					class="w-full text-sm bg-[var(--surface2)] border border-[var(--border)] rounded px-2.5 py-1.5 text-[var(--text)] focus:outline-none focus:border-[var(--border-strong)]"
   276→				>
   277→					${stages.map((s) => html`<option key=${s} value=${s}>${t(`contacts.stages.${s}`)}</option>`)}
   278→				</select>
   279→			</div>
   280→			<div class="grid grid-cols-2 gap-3">
   281→				<div>
   282→					<label class="block text-xs text-[var(--muted)] mb-1">${t("form.source")}</label>
   283→					<input
   284→						type="text"
   285→						value=${source}
   286→						onInput=${(e) => setSource(e.target.value)}
   287→						placeholder=${t("form.sourcePlaceholder")}
   288→						class="w-full text-sm bg-[var(--surface2)] border border-[var(--border)] rounded px-2.5 py-1.5 text-[var(--text)] focus:outline-none focus:border-[var(--border-strong)]"
   289→					/>
   290→				</div>
   291→				<div>
   292→					<label class="block text-xs text-[var(--muted)] mb-1">${t("form.externalId")}</label>
   293→					<input
   294→						type="text"
   295→						value=${externalId}
   296→						onInput=${(e) => setExternalId(e.target.value)}
   297→						placeholder=${t("form.externalIdPlaceholder")}
   298→						class="w-full text-sm bg-[var(--surface2)] border border-[var(--border)] rounded px-2.5 py-1.5 text-[var(--text)] focus:outline-none focus:border-[var(--border-strong)]"
   299→					/>
   300→				</div>
   301→			</div>
   302→			${error && html`<p class="text-xs text-[var(--error)]">${error}</p>`}
   303→		</div>
   304→		<div class="flex gap-2 justify-end">
   305→			<button type="button" class="provider-btn provider-btn-secondary" onClick=${onClose}>${t("form.cancel")}</button>
   306→			<button type="submit" class="provider-btn" disabled=${saving}>${saving ? "\u2026" : isEdit ? t("form.save") : t("form.create")}</button>
   307→		</div>
   308→	</form>`;
   309→}
