   311→// ── MatterForm modal ──────────────────────────────────────────
   312→function MatterForm({ matter, contactId, onClose, onSaved }) {
   313→	var { t } = useTranslation("crm");
   314→	var isEdit = !!matter?.id;
   315→
   316→	var [title, setTitle] = useState(matter?.title || "");
   317→	var [description, setDescription] = useState(matter?.description || "");
   318→	var [status, setStatus] = useState(matter?.status || "open");
   319→	var [phase, setPhase] = useState(matter?.phase || "intake");
   320→	var [practiceArea, setPracticeArea] = useState(matter?.practiceArea || "other");
   321→	var [saving, setSaving] = useState(false);
   322→	var [error, setError] = useState(null);
   323→
   324→	function onSubmit(e) {
   325→		e.preventDefault();
   326→		if (!title.trim()) {
   327→			setError(t("form.matterTitleRequired"));
   328→			return;
   329→		}
   330→		setSaving(true);
   331→		setError(null);
   332→		var params = {
   333→			id: matter?.id || newId(),
   334→			title: title.trim(),
   335→			description: description.trim() || null,
   336→			contactId: contactId || matter?.contactId || null,
   337→			status,
   338→			phase,
   339→			practiceArea,
   340→			createdAt: matter?.createdAt,
   341→		};
   342→		sendRpc("crm.matters.upsert", params).then((res) => {
   343→			setSaving(false);
   344→			if (!res?.ok) {
   345→				setError(t("errors.saveFailed"));
   346→				return;
   347→			}
   348→			onSaved();
   349→		});
   350→	}
   351→
   352→	var statuses = ["open", "on_hold", "closed", "archived"];
   353→	var phases = ["intake", "discovery", "negotiation", "resolution", "review", "closed"];
   354→	var practiceAreas = [
   355→		"corporate",
   356→		"employment",
   357→		"family_law",
   358→		"immigration",
   359→		"intellectual_property",
   360→		"litigation",
   361→		"real_estate",
   362→		"tax",
   363→		"other",
   364→	];
   365→
   366→	return html`<form onSubmit=${onSubmit}>
   367→		<div class="flex flex-col gap-3 mb-4">
   368→			<div>
   369→				<label class="block text-xs text-[var(--muted)] mb-1">${t("form.matterTitle")} *</label>
   370→				<input
   371→					type="text"
   372→					value=${title}
   373→					onInput=${(e) => setTitle(e.target.value)}
   374→					placeholder=${t("form.matterTitlePlaceholder")}
   375→					class="w-full text-sm bg-[var(--surface2)] border border-[var(--border)] rounded px-2.5 py-1.5 text-[var(--text)] focus:outline-none focus:border-[var(--border-strong)]"
   376→					autofocus
   377→				/>
   378→			</div>
   379→			<div>
   380→				<label class="block text-xs text-[var(--muted)] mb-1">${t("form.description")}</label>
   381→				<textarea
   382→					value=${description}
   383→					onInput=${(e) => setDescription(e.target.value)}
   384→					placeholder=${t("form.descriptionPlaceholder")}
   385→					rows="2"
   386→					class="w-full text-sm bg-[var(--surface2)] border border-[var(--border)] rounded px-2.5 py-1.5 text-[var(--text)] focus:outline-none focus:border-[var(--border-strong)] resize-none"
   387→				/>
   388→			</div>
   389→			<div class="grid grid-cols-3 gap-3">
   390→				<div>
   391→					<label class="block text-xs text-[var(--muted)] mb-1">${t("form.status")}</label>
   392→					<select
   393→						value=${status}
   394→						onChange=${(e) => setStatus(e.target.value)}
   395→						class="w-full text-sm bg-[var(--surface2)] border border-[var(--border)] rounded px-2.5 py-1.5 text-[var(--text)] focus:outline-none focus:border-[var(--border-strong)]"
   396→					>
   397→						${statuses.map((s) => html`<option key=${s} value=${s}>${t(`matters.status.${s}`)}</option>`)}
   398→					</select>
   399→				</div>
   400→				<div>
   401→					<label class="block text-xs text-[var(--muted)] mb-1">${t("form.phase")}</label>
   402→					<select
   403→						value=${phase}
   404→						onChange=${(e) => setPhase(e.target.value)}
   405→						class="w-full text-sm bg-[var(--surface2)] border border-[var(--border)] rounded px-2.5 py-1.5 text-[var(--text)] focus:outline-none focus:border-[var(--border-strong)]"
   406→					>
   407→						${phases.map((p) => html`<option key=${p} value=${p}>${t(`matters.phase.${p}`)}</option>`)}
   408→					</select>
   409→				</div>
   410→				<div>
   411→					<label class="block text-xs text-[var(--muted)] mb-1">${t("form.practiceArea")}</label>
   412→					<select
   413→						value=${practiceArea}
   414→						onChange=${(e) => setPracticeArea(e.target.value)}
   415→						class="w-full text-sm bg-[var(--surface2)] border border-[var(--border)] rounded px-2.5 py-1.5 text-[var(--text)] focus:outline-none focus:border-[var(--border-strong)]"
   416→					>
   417→						${practiceAreas.map((a) => html`<option key=${a} value=${a}>${t(`matters.practiceArea.${a}`)}</option>`)}
   418→					</select>
   419→				</div>
   420→			</div>
   421→			${error && html`<p class="text-xs text-[var(--error)]">${error}</p>`}
   422→		</div>
   423→		<div class="flex gap-2 justify-end">
   424→			<button type="button" class="provider-btn provider-btn-secondary" onClick=${onClose}>${t("form.cancel")}</button>
   425→			<button type="submit" class="provider-btn" disabled=${saving}>${saving ? "\u2026" : isEdit ? t("form.save") : t("form.create")}</button>
   426→		</div>
   427→	</form>`;
   428→}
