   430→// ── InteractionForm modal ─────────────────────────────────────
   431→function InteractionForm({ contactId, onClose, onSaved }) {
   432→	var { t } = useTranslation("crm");
   433→	var matterList = matters.value;
   434→
   435→	var [kind, setKind] = useState("note");
   436→	var [summary, setSummary] = useState("");
   437→	var [matterId, setMatterId] = useState("");
   438→	var [saving, setSaving] = useState(false);
   439→	var [error, setError] = useState(null);
   440→
   441→	function onSubmit(e) {
   442→		e.preventDefault();
   443→		if (!summary.trim()) {
   444→			setError(t("form.summaryRequired"));
   445→			return;
   446→		}
   447→		setSaving(true);
   448→		setError(null);
   449→		var params = {
   450→			id: newId(),
   451→			contactId,
   452→			kind,
   453→			summary: summary.trim(),
   454→			matterId: matterId || null,
   455→		};
   456→		sendRpc("crm.interactions.upsert", params).then((res) => {
   457→			setSaving(false);
   458→			if (!res?.ok) {
   459→				setError(t("errors.saveFailed"));
   460→				return;
   461→			}
   462→			onSaved();
   463→		});
   464→	}
   465→
   466→	var kinds = ["call", "email", "message", "meeting", "note", "document"];
   467→
   468→	return html`<form onSubmit=${onSubmit}>
   469→		<div class="flex flex-col gap-3 mb-4">
   470→			<div class="grid grid-cols-2 gap-3">
   471→				<div>
   472→					<label class="block text-xs text-[var(--muted)] mb-1">${t("form.kind")}</label>
   473→					<select
   474→						value=${kind}
   475→						onChange=${(e) => setKind(e.target.value)}
   476→						class="w-full text-sm bg-[var(--surface2)] border border-[var(--border)] rounded px-2.5 py-1.5 text-[var(--text)] focus:outline-none focus:border-[var(--border-strong)]"
   477→					>
   478→						${kinds.map((k) => html`<option key=${k} value=${k}>${t(`interactions.kind.${k}`)}</option>`)}
   479→					</select>
   480→				</div>
   481→				${
   482→					matterList.length > 0 &&
   483→					html`<div>
   484→						<label class="block text-xs text-[var(--muted)] mb-1">${t("form.matter")}</label>
   485→						<select
   486→							value=${matterId}
