   516→// ── Modal wrapper (inline) ────────────────────────────────────
   517→function CrmModal({ title, onClose, children }) {
   518→	useEffect(() => {
   519→		function onKey(e) {
   520→			if (e.key === "Escape") onClose();
   521→		}
   522→		document.addEventListener("keydown", onKey);
   523→		return () => document.removeEventListener("keydown", onKey);
   524→	}, [onClose]);
   525→
   526→	return html`<div
   527→		class="fixed inset-0 z-50 flex items-center justify-center p-4"
   528→		style="background:rgba(0,0,0,0.5)"
   529→		onClick=${(e) => e.target === e.currentTarget && onClose()}
   530→	>
   531→		<div class="bg-[var(--surface)] border border-[var(--border)] rounded-lg shadow-xl w-full max-w-md max-h-[90vh] overflow-y-auto">
   532→			<div class="flex items-center justify-between px-4 py-3 border-b border-[var(--border)]">
   533→				<h2 class="text-sm font-semibold text-[var(--text-strong)]">${title}</h2>
   534→				<button
   535→					type="button"
   536→					class="text-[var(--muted)] hover:text-[var(--text)] bg-transparent border-0 cursor-pointer p-1 rounded"
   537→					onClick=${onClose}
   538→				>
   539→					<span class="icon icon-sm icon-x"></span>
   540→				</button>
   541→			</div>
   542→			<div class="p-4">${children}</div>
   543→		</div>
   544→	</div>`;
   545→}
