   955→				? html`<p class="text-sm text-[var(--muted)]">Loading\u2026</p>`
   956→				: list.length === 0
   957→					? html`<p class="text-sm text-[var(--muted)]">${t("matters.empty")}</p>`
   958→					: html`<div class="flex flex-col gap-2">
   959→							${list.map(
   960→								(m) => html`<div
   961→									key=${m.id}
   962→									class="rounded-lg border border-[var(--border)] p-3 hover:bg-[var(--bg-hover)] transition-colors"
   963→								>
   964→									<div class="flex items-start justify-between gap-2">
   965→										<div class="flex-1 min-w-0">
   966→											<div class="flex items-center gap-2 flex-wrap">
   967→												<span class="text-sm font-medium text-[var(--text-strong)] truncate">${m.title}</span>
   968→												<span class="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium ${MATTER_STATUS_COLORS[m.status] || ""}">${t(`matters.status.${m.status}`)}</span>
   969→											</div>
   970→											<div class="flex items-center gap-2 mt-1 text-xs text-[var(--muted)] flex-wrap">
   971→												<span>${t(`matters.phase.${m.phase}`)}</span>
   972→												<span>·</span>
   973→												<span>${t(`matters.practiceArea.${m.practiceArea}`)}</span>
   974→												${m.createdAt && html`<span>· ${formatDate(m.createdAt)}</span>`}
   975→											</div>
   976→											${m.description && html`<p class="text-xs text-[var(--muted)] mt-1 line-clamp-2">${m.description}</p>`}
   977→										</div>
   978→										<div class="flex gap-1.5 shrink-0">
   979→											<button class="provider-btn provider-btn-sm provider-btn-secondary" onClick=${() => onEdit(m)}>Edit</button>
   980→											<button class="provider-btn provider-btn-sm provider-btn-danger" onClick=${() => onDelete(m)}>Delete</button>
   981→										</div>
   982→									</div>
   983→								</div>`,
   984→							)}
   985→						</div>`
   986→		}
   987→	</div>`;
   988→}
   989→
   990→// ── Interactions tab ──────────────────────────────────────────
   991→function InteractionsTab({ t, onAdd, onDelete }) {
   992→	var list = interactions.value;
   993→
   994→	return html`<div class="p-4">
   995→		<div class="flex items-center justify-between mb-3">
   996→			<h3 class="text-sm font-medium text-[var(--text-strong)]">${t("interactions.title")}</h3>
   997→			<button class="provider-btn provider-btn-sm" onClick=${onAdd}>${t("interactions.add")}</button>
   998→		</div>
   999→		${
  1000→			loadingInteractions.value
  1001→				? html`<p class="text-sm text-[var(--muted)]">Loading\u2026</p>`
  1002→				: list.length === 0
  1003→					? html`<p class="text-sm text-[var(--muted)]">${t("interactions.empty")}</p>`
  1004→					: html`<div class="flex flex-col gap-2">
  1005→							${list.map(
  1006→								(i) => html`<div
  1007→									key=${i.id}
  1008→									class="rounded-lg border border-[var(--border)] p-3"
  1009→								>
  1010→									<div class="flex items-start justify-between gap-2">
  1011→										<div class="flex items-start gap-2 flex-1 min-w-0">
  1012→											<span class="icon ${INTERACTION_KIND_ICONS[i.kind] || "icon-file"} text-[var(--muted)] mt-0.5 shrink-0" style="font-size:0.9rem"></span>
  1013→											<div class="flex-1 min-w-0">
  1014→												<div class="flex items-center gap-2">
  1015→													<span class="text-xs font-medium text-[var(--text)]">${t(`interactions.kind.${i.kind}`)}</span>
  1016→													${i.createdAt && html`<span class="text-xs text-[var(--muted)]">${formatDateTime(i.createdAt)}</span>`}
  1017→												</div>
  1018→												<p class="text-sm text-[var(--text)] mt-0.5">${i.summary}</p>
  1019→											</div>
  1020→										</div>
  1021→										<button class="provider-btn provider-btn-sm provider-btn-danger shrink-0" onClick=${() => onDelete(i)}>Delete</button>
  1022→									</div>
  1023→								</div>`,
  1024→							)}
  1025→						</div>`
  1026→		}
  1027→	</div>`;
  1028→}
  1029→
  1030→// ── Channels tab ──────────────────────────────────────────────
  1031→function ChannelsTab({ t }) {
  1032→	var list = channels.value;
  1033→
  1034→	return html`<div class="p-4">
  1035→		<h3 class="text-sm font-medium text-[var(--text-strong)] mb-3">${t("detail.channels")}</h3>
  1036→		${
  1037→			loadingChannels.value
  1038→				? html`<p class="text-sm text-[var(--muted)]">Loading\u2026</p>`
  1039→				: list.length === 0
  1040→					? html`<p class="text-sm text-[var(--muted)]">${t("channels.empty")}</p>`
  1041→					: html`<div class="flex flex-col gap-2">
  1042→							${list.map(
  1043→								(ch) => html`<div
  1044→									key=${ch.id}
  1045→									class="flex items-center gap-2 rounded-lg border border-[var(--border)] px-3 py-2"
  1046→								>
  1047→									<span class="text-xs font-mono text-[var(--muted)] bg-[var(--surface2)] px-2 py-0.5 rounded">${ch.channelType}</span>
  1048→									<span class="text-sm text-[var(--text)] truncate">${ch.displayName || ch.channelId}</span>
  1049→									${ch.verified && html`<span class="text-xs text-green-600 ml-auto">Verified</span>`}
  1050→								</div>`,
  1051→							)}
  1052→						</div>`
  1053→		}
  1054→	</div>`;
  1055→}
  1056→
  1057→// ── Root CRM component ────────────────────────────────────────
  1058→function CrmRoot({ contactId }) {
  1059→	if (contactId) {
  1060→		return html`<${ContactDetailPage} contactId=${contactId} />`;
  1061→	}
  1062→	return html`<${ContactListPage} />`;
  1063→}
  1064→
  1065→// ── Page lifecycle ─────────────────────────────────────────────
  1066→var containerRef = null;
  1067→
  1068→export function initCrm(container, param) {
  1069→	containerRef = container;
  1070→	container.style.cssText = "flex-direction:column;padding:0;overflow:hidden;";
  1071→
  1072→	var contactId = param || null;
  1073→	currentContactId.value = contactId;
  1074→
  1075→	if (!contactId) {
  1076→		loadContacts();
  1077→	}
  1078→
  1079→	render(html`<${CrmRoot} contactId=${contactId} />`, container);
  1080→}
  1081→
  1082→export function teardownCrm() {
  1083→	if (containerRef) render(null, containerRef);
  1084→	containerRef = null;
  1085→	// Reset signals
  1086→	contacts.value = [];
  1087→	loadingContacts.value = true;
  1088→	searchQuery.value = "";
  1089→	stageFilter.value = "";
  1090→	currentContactId.value = null;
  1091→	contactDetail.value = null;
  1092→	matters.value = [];
  1093→	interactions.value = [];
  1094→	channels.value = [];
  1095→	detailTab.value = "overview";
  1096→}
  1097→
  1098→// ── Route registration ────────────────────────────────────────
  1099→if (gon.get("crm_enabled")) {
  1100→	registerPrefix(routes.crm, initCrm, teardownCrm);
