export function teardownCrm() {
	if (containerRef) render(null, containerRef);
	containerRef = null;
	// Reset signals
	contacts.value = [];
	loadingContacts.value = true;
	searchQuery.value = "";
	stageFilter.value = "";
	currentContactId.value = null;
	contactDetail.value = null;
	matters.value = [];
	interactions.value = [];
	channels.value = [];
	detailTab.value = "overview";
}

